"use client";
import { useState, useEffect } from "react";
import { ChevronDown, Wallet as WalletIcon } from "lucide-react";

export default function ExpensePage() {
    const [wallets, setWallets] = useState<any[]>([]);
    const [selectedWalletId, setSelectedWalletId] = useState("");
    const [amount, setAmount] = useState("");
    const [category, setCategory] = useState("Makan & Minum");
    const [description, setDescription] = useState("");
    const [loading, setLoading] = useState(false);

    // Ambil daftar akun (BCA, GoPay, dll) dari database
    useEffect(() => {
        fetch("/api/dashboard/summary") // Kita pakai API yang sudah ada
        .then(res => res.json())
        .then(data => {
            setWallets(data.walletDetails || []);
            if (data.walletDetails?.length > 0) setSelectedWalletId(data.walletDetails[0].id);
        });
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        
        const res = await fetch("/api/transactions/expense", {
        method: "POST",
        body: JSON.stringify({ amount, description, walletId: Number(selectedWalletId), categoryName: category }),
        });

        if (res.ok) {
        alert("Catatan pengeluaran berhasil disimpan!");
        window.location.href = "/dashboard";
        }
        setLoading(false);
    };

    return (
        <div className="max-w-xl mx-auto mt-10">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
            <h2 className="text-2xl font-bold text-slate-800 mb-8 flex items-center gap-2">
            <span className="p-2 bg-red-50 text-red-500 rounded-xl">💸</span>
            Catat Pengeluaran
            </h2>

            <form onSubmit={handleSubmit} className="space-y-6">
            {/* Input Nominal */}
            <div>
                <label className="text-sm font-semibold text-slate-500 ml-1">Nominal Jajan</label>
                <div className="relative mt-2">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 font-bold text-slate-400">Rp</span>
                <input 
                    type="number" required placeholder="0"
                    className="w-full p-4 pl-12 bg-slate-50 border-none rounded-2xl text-2xl font-bold text-slate-800 focus:ring-2 focus:ring-red-500"
                    onChange={(e) => setAmount(e.target.value)}
                />
                </div>
            </div>

            {/* Pilih Akun (Wallet) */}
            <div>
                <label className="text-sm font-semibold text-slate-500 ml-1">Bayar Pakai</label>
                <div className="relative mt-2">
                <select 
                    required
                    className="w-full p-4 pl-12 bg-slate-50 border-none rounded-2xl appearance-none text-slate-700 font-medium cursor-pointer"
                    onChange={(e) => setSelectedWalletId(e.target.value)}
                >
                    {wallets.map((w) => (
                    <option key={w.id} value={w.id}>{w.name} (Sisa: Rp {w.balance.toLocaleString()})</option>
                    ))}
                </select>
                <WalletIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                </div>
            </div>

            {/* Input Keterangan */}
            <div>
                <label className="text-sm font-semibold text-slate-500 ml-1">Keterangan (Opsional)</label>
                <input 
                type="text" placeholder="Beli apa hari ini?"
                className="w-full p-4 mt-2 bg-slate-50 border-none rounded-2xl text-slate-700"
                onChange={(e) => setDescription(e.target.value)}
                />
            </div>

            <button 
                disabled={loading}
                className="w-full bg-slate-900 text-white p-5 rounded-2xl font-bold text-lg hover:bg-slate-800 transition-all active:scale-95 disabled:opacity-50"
            >
                {loading ? "Menyimpan..." : "Simpan Pengeluaran"}
            </button>
            </form>
        </div>
        </div>
    );
}